    public static void main(String[] args) {
        int a = 15;
        int b = 4;

        // Addition
        System.out.println(a + " + " + b + " = " + (a + b));
        // Subtraction
        System.out.println(a + " - " + b + " = " + (a - b));
        // Multiplication
        System.out.println(a + " * " + b + " = " + (a * b));
        // Division (integer division truncates decimals)
        System.out.println(a + " / " + b + " = " + (a / b));
        // Remainder
        System.out.println(a + " % " + b + " = " + (a % b));
    }
}

