// Grade management: comprehensive exercise for arrays, loops, conditionals
public class GradeManager {
    public static void main(String[] args) {
        // Manage scores of 5 students in array
        int[] scores = {85, 72, 95, 90, 68};

        int sum = 0;
        int max = scores[0];  // Initial value for max score
        int min = scores[0];  // Initial value for min score

        // Traverse all elements to find sum, max, min
        for (int score : scores) {
            sum += score;
            if (score > max) {
                max = score;
            }
            if (score < min) {
                min = score;
            }
        }

        // Average (cast to double to preserve decimals)
        double average = (double) sum / scores.length;

        System.out.println("Total: " + sum);
        System.out.println("Average: " + average);
        System.out.println("Highest: " + max);
        System.out.println("Lowest: " + min);
    }
}

