// ===== ConfigParser.java =====

public class ConfigParser {
    static void parseLine(String line) throws ConfigException {
        try {
            if (!line.contains("=")) {
                throw new FormatException("Invalid format: '=' not found");
            }
            String[] parts = line.split("=", 2);
            String key = parts[0].trim();
            String value = parts[1].trim();

            // Type check for numeric keys
            if (key.equals("port") || key.equals("timeout")) {
                try {
                    Integer.parseInt(value);
                } catch (NumberFormatException e) {
                    throw new TypeException("Invalid value type: '" + value + "' is not an integer");
                }
            }

            System.out.println(line + " → OK: " + key + " = " + value);
        } catch (FormatException | TypeException e) {
            // Chain cause exception and rethrow as ConfigException
            throw new ConfigException("Failed to parse configuration", e);
        }
    }

    public static void main(String[] args) {
        String[] lines = {"host=localhost", "port=8080", "invalid_line", "timeout=abc"};

        for (String line : lines) {
            try {
                parseLine(line);
            } catch (ConfigException e) {
                System.out.println(line + " → Error: " + e.getMessage());
                if (e.getCause() != null) {
                    System.out.println("  Cause: " + e.getCause().getMessage());
                }
            }
        }
    }
}

