@FunctionalInterface
public interface Validator<T> {
    String validate(T value); // null = OK, non-null = error message
}

// ===== Validators.java =====
public class Validators {
    public static Validator<String> notNull() {
        return value -> value == null ? "Value is null" : null;
    }

    public static Validator<String> minLength(int min) {
        return value -> {
            if (value == null) return null; // Null check is handled by a separate rule
            return value.length() < min ? min + " or more characters required" : null;
        };
    }

    public static Validator<String> matchesEmail() {
        return value -> {
            if (value == null) return null;
            return value.matches(".+@.+\\..+") ? null : "Invalid email format";
        };
    }
}

// ===== ValidationChain.java =====
import java.util.ArrayList;
import java.util.List;

public class ValidationChain<T> {
    private final List<Validator<T>> validators = new ArrayList<>();

    public ValidationChain<T> addRule(Validator<T> validator) {
        validators.add(validator);
        return this;
    }

    public void validate(T value) throws ValidationException {
        List<String> errors = new ArrayList<>();
        for (Validator<T> v : validators) {
            String error = v.validate(value);
            if (error != null) {
                errors.add(error);
            }
        }
        if (!errors.isEmpty()) {
            throw new ValidationException(errors);
        }
    }
}

// ===== ValidationDemo.java =====
public class ValidationDemo {
    public static void main(String[] args) {
        ValidationChain<String> emailValidator = new ValidationChain<String>()
            .addRule(Validators.notNull())
            .addRule(Validators.minLength(3))
            .addRule(Validators.matchesEmail());

        // Normal
        tryValidate(emailValidator, "taro@example.com");
        // null
        tryValidate(emailValidator, null);
        // Short and invalid format
        tryValidate(emailValidator, "ab");
    }

    private static void tryValidate(ValidationChain<String> chain, String value) {
        try {
            chain.validate(value);
            System.out.println("Validation success: " + value);
        } catch (ValidationException e) {
            System.out.println("Validation errors:");
            for (String err : e.getErrors()) {
                System.out.println("  - " + err);
            }
        }
    }
}

