// Password strength: comprehensive exercise for String API and char operations
public class PasswordChecker {
    static void checkStrength(String password) {
        int score = 0;

        // 1. Length (8 or more characters)
        if (password.length() >= 8) score++;

        boolean hasUpper = false, hasLower = false;
        boolean hasDigit = false, hasSymbol = false;

        for (int i = 0; i < password.length(); i++) {
            char c = password.charAt(i);
            if (Character.isUpperCase(c)) hasUpper = true;
            else if (Character.isLowerCase(c)) hasLower = true;
            else if (Character.isDigit(c)) hasDigit = true;
            else hasSymbol = true;
        }

        if (hasUpper) score++;
        if (hasLower) score++;
        if (hasDigit) score++;
        if (hasSymbol) score++;

        String level;
        if (score >= 5) level = "Strong";
        else if (score >= 3) level = "Medium";
        else level = "Weak";

        System.out.println("Password: " + password + " → Strength: " + level + " (Score: " + score + "/5)");
    }

    public static void main(String[] args) {
        checkStrength("abc");
        checkStrength("Hello123");
        checkStrength("P@ssw0rd!");
    }
}

