    private AppConfig() {}

    public static class Builder {
        private final AppConfig config = new AppConfig();

        public Builder set(String key, String value) {
            config.entries.put(key, new ConfigValue.StringVal(value));
            return this;
        }

        public Builder set(String key, int value) {
            config.entries.put(key, new ConfigValue.IntVal(value));
            return this;
        }

        public Builder set(String key, boolean value) {
            config.entries.put(key, new ConfigValue.BoolVal(value));
            return this;
        }

        public Builder set(String key, List<String> values) {
            config.entries.put(key, new ConfigValue.ListVal(values));
            return this;
        }

        public AppConfig build() {
            return config;
        }
    }

    public void printAll() {
        entries.forEach((key, value) -> {
            String display = switch (value) {
                case ConfigValue.StringVal s -> s.value() + " (String)";
                case ConfigValue.IntVal i -> i.value() + " (Int)";
                case ConfigValue.BoolVal b -> b.value() + " (Bool)";
                case ConfigValue.ListVal l -> l.values() + " (List, " + l.values().size() + " items)";
            };
            System.out.println(key + " = " + display);
        });
    }
}

