class InventoryManager {
    private Map<String, Integer> stock = new LinkedHashMap<>();

    void addStock(String item, int qty) {
        stock.put(item, stock.getOrDefault(item, 0) + qty);
    }

    void removeStock(String item, int qty) {
        int current = stock.getOrDefault(item, 0);
        stock.put(item, Math.max(0, current - qty));
    }

    void printInventory() {
        System.out.println("=== Inventory List ===");
        for (Map.Entry<String, Integer> e : stock.entrySet()) {
            System.out.println(e.getKey() + ": " + e.getValue() + " units");
        }
    }

    void printOutOfStock() {
        List<String> outOfStock = new ArrayList<>();
        for (Map.Entry<String, Integer> e : stock.entrySet()) {
            if (e.getValue() <= 0) outOfStock.add(e.getKey());
        }
        System.out.println("Out of stock: " + outOfStock);
    }
}

