// ===== CipherPipeline.java =====
import java.util.function.Function;

public class CipherPipeline {
    // Caesar cipher (+shift)
    static Function<String, String> caesarEncrypt(int shift) {
        return s -> {
            StringBuilder sb = new StringBuilder();
            for (char c : s.toCharArray()) {
                sb.append((char)(c + shift));
            }
            return sb.toString();
        };
    }

    // String reversal
    static Function<String, String> reverse() {
        return s -> new StringBuilder(s).reverse().toString();
    }

    // Base64 encode / decode
    static Function<String, String> base64Encode() {
        return s -> java.util.Base64.getEncoder().encodeToString(s.getBytes());
    }

    static Function<String, String> base64Decode() {
        return s -> new String(java.util.Base64.getDecoder().decode(s));
    }

    public static void main(String[] args) {
        String original = "Hello";

        // Encryption pipeline
        Function<String, String> encrypt = caesarEncrypt(3)
            .andThen(reverse())
            .andThen(base64Encode());

        // Decryption pipeline (reverse order × inverse operations)
        Function<String, String> decrypt = base64Decode()
            .andThen(reverse())
            .andThen(caesarEncrypt(-3));

        String encrypted = encrypt.apply(original);
        String decrypted = decrypt.apply(encrypted);

        System.out.println("Original: " + original);
        System.out.println("Encrypted: " + encrypted);
        System.out.println("Decrypted: " + decrypted);
        System.out.println("Verification: " + (original.equals(decrypted) ? "Match" : "Mismatch"));
    }
}

// ===== CustomCollectors.java =====
import java.util.*;
import java.util.stream.*;

public class CustomCollectors {

    // --- Statistics ---
    public static class Statistics {
        long count;
        long sum;
        int min = Integer.MAX_VALUE;
        int max = Integer.MIN_VALUE;

        void accept(int value) {
            count++;
            sum += value;
            min = Math.min(min, value);
            max = Math.max(max, value);
        }

        Statistics combine(Statistics other) {
            count += other.count;
            sum += other.sum;
            min = Math.min(min, other.min);
            max = Math.max(max, other.max);
            return this;
        }

        @Override
        public String toString() {
            return "Count: " + count + "\nTotal: " + sum
                + "\nAverage: " + (count > 0 ? (double) sum / count : 0)
                + "\nMin: " + min + "\nMax: " + max;
        }
    }

    public static Collector<Integer, Statistics, Statistics> toStats() {
        return Collector.of(
            Statistics::new,
            (stats, val) -> stats.accept(val),
            (s1, s2) -> s1.combine(s2)
        );
    }

    // --- Top N ---
    public static Collector<Integer, PriorityQueue<Integer>, List<Integer>> topN(int n) {
        return Collector.of(
            PriorityQueue::new, // min-heap
            (pq, val) -> {
                pq.offer(val);
                if (pq.size() > n) pq.poll(); // Remove the minimum
            },
            (pq1, pq2) -> {
                pq1.addAll(pq2);
                while (pq1.size() > n) pq1.poll();
                return pq1;
            },
            pq -> {
                List<Integer> result = new ArrayList<>(pq);
                result.sort(Comparator.reverseOrder());
                return result;
            }
        );
    }

    public static void main(String[] args) {
        List<Integer> data = List.of(30, 10, 50, 70, 20, 90, 80, 10);

        Statistics stats = data.stream().collect(toStats());
        System.out.println("=== Statistics ===");
        System.out.println(stats);

        List<Integer> top3 = data.stream().collect(topN(3));
        System.out.println("\n=== Top 3 ===");
        System.out.println(top3);
    }
}

