// TransactionDemo.java
// Transaction: comprehensive exercise for commit/rollback
import java.sql.*;

public class TransactionDemo {
    public static void main(String[] args) throws Exception {
        String url = "jdbc:h2:mem:bank";
        try (Connection conn = DriverManager.getConnection(url, "sa", "")) {
            // Setup
            try (Statement s = conn.createStatement()) {
                s.execute("CREATE TABLE accounts(name VARCHAR(10) PRIMARY KEY, balance INT)");
                s.execute("INSERT INTO accounts VALUES('A', 10000)");
                s.execute("INSERT INTO accounts VALUES('B', 5000)");
            }
            printBalances(conn, "Before transfer");

            // Transfer 1: Success case
            transfer(conn, "A", "B", 3000);
            printBalances(conn, "After transfer");

            System.out.println("---");

            // Transfer 2: Insufficient balance → rollback
            transfer(conn, "A", "B", 20000);
            printBalances(conn, "Balance unchanged");
        }
    }

    static void transfer(Connection conn, String from, String to, int amount) throws SQLException {
        System.out.println("Transfer: " + from + "→" + to + " " + amount + "circle");
        conn.setAutoCommit(false);
        try {
            // Balance check
            int balance = getBalance(conn, from);
            if (balance < amount) {
                throw new SQLException("Insufficient balance");
            }
            // Withdrawal
            updateBalance(conn, from, -amount);
            // Deposit
            updateBalance(conn, to, amount);
            conn.commit();
        } catch (SQLException e) {
            conn.rollback();
            System.out.println("Error: " + e.getMessage() + " → Rollback");
        } finally {
            conn.setAutoCommit(true);
        }
    }

    static int getBalance(Connection conn, String name) throws SQLException {
        try (PreparedStatement ps = conn.prepareStatement("SELECT balance FROM accounts WHERE name=?")) {
            ps.setString(1, name);
            ResultSet rs = ps.executeQuery();
            rs.next();
            return rs.getInt(1);
        }
    }

    static void updateBalance(Connection conn, String name, int delta) throws SQLException {
        try (PreparedStatement ps = conn.prepareStatement("UPDATE accounts SET balance = balance + ? WHERE name = ?")) {
            ps.setInt(1, delta);
            ps.setString(2, name);
            ps.executeUpdate();
        }
    }

    static void printBalances(Connection conn, String label) throws SQLException {
        try (Statement s = conn.createStatement();
             ResultSet rs = s.executeQuery("SELECT name, balance FROM accounts ORDER BY name")) {
            StringBuilder sb = new StringBuilder(label + ": ");
            while (rs.next()) {
                if (sb.length() > label.length() + 2) sb.append(", ");
                sb.append(rs.getString(1) + "=" + rs.getInt(2) + "circle");
            }
            System.out.println(sb);
        }
    }
}

