// ThreadSafeCounter.java
// Thread-safe counter: comprehensive exercise for synchronized and AtomicInteger
import java.util.concurrent.atomic.AtomicInteger;

public class ThreadSafeCounter {
    static int unsafeCount = 0;
    static int safeCount = 0;
    static AtomicInteger atomicCount = new AtomicInteger(0);

    static synchronized void safeIncrement() {
        safeCount++;
    }

    public static void main(String[] args) throws InterruptedException {
        int numThreads = 10;
        int iterations = 1000;

        // === Without synchronized ===
        Thread[] threads1 = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads1[i] = new Thread(() -> {
                for (int j = 0; j < iterations; j++) unsafeCount++;
            });
            threads1[i].start();
        }
        for (Thread t : threads1) t.join();
        System.out.println("=== Without synchronized ===");
        System.out.println("Expected: " + (numThreads * iterations) + ", Actual: " + unsafeCount);

        // === With synchronized ===
        Thread[] threads2 = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads2[i] = new Thread(() -> {
                for (int j = 0; j < iterations; j++) safeIncrement();
            });
            threads2[i].start();
        }
        for (Thread t : threads2) t.join();
        System.out.println("=== With synchronized ===");
        System.out.println("Expected: " + (numThreads * iterations) + ", Actual: " + safeCount);

        // === AtomicInteger ===
        Thread[] threads3 = new Thread[numThreads];
        for (int i = 0; i < numThreads; i++) {
            threads3[i] = new Thread(() -> {
                for (int j = 0; j < iterations; j++) atomicCount.incrementAndGet();
            });
            threads3[i].start();
        }
        for (Thread t : threads3) t.join();
        System.out.println("=== AtomicInteger ===");
        System.out.println("Expected: " + (numThreads * iterations) + ", Actual: " + atomicCount.get());
    }
}

