// Directory exploration: comprehensive exercise for NIO2 and Stream
import java.io.IOException;
import java.nio.file.*;
import java.util.*;
import java.util.stream.*;

public class DirectoryExplorer {
    public static void main(String[] args) throws IOException {
        Path dir = Path.of(".");  // Current directory

        System.out.println("=== Directory Exploration: " + dir.toAbsolutePath() + " ===");

        // Group files by extension
        try (Stream<Path> walk = Files.walk(dir)) {
            Map<String, List<Path>> grouped = walk
                .filter(Files::isRegularFile)
                .collect(Collectors.groupingBy(p -> {
                    String name = p.getFileName().toString();
                    int dot = name.lastIndexOf('.');
                    return dot > 0 ? name.substring(dot) : "(no extension)";
                }));

            // Display info for each extension
            grouped.entrySet().stream()
                .sorted(Map.Entry.comparingByKey())
                .forEach(e -> {
                    long totalSize = e.getValue().stream()
                        .mapToLong(p -> {
                            try { return Files.size(p); }
                            catch (IOException ex) { return 0; }
                        }).sum();
                    System.out.printf("%s files: %d (Total: %.1fKB)%n",
                        e.getKey(), e.getValue().size(), totalSize / 1024.0);
                });
        }
    }
}

