        List<Callable<String>> tasks = List.of(
            () -> { Thread.sleep(500);  return "Calculation done (value: 100)"; },
            () -> { Thread.sleep(300);  return "Calculation done (value: 200)"; },
            () -> { Thread.sleep(100);  return "Calculation done (value: 300)"; }
        );

        // Submit tasks
        List<Future<String>> futures = new ArrayList<>();
        for (Callable<String> task : tasks) {
            futures.add(executor.submit(task));
        }
        System.out.println("Tasks submitted: " + futures.size() + " items");

        // Get results
        for (int i = 0; i < futures.size(); i++) {
            String result = futures.get(i).get();  // Blocking wait
            System.out.println("Result" + (i + 1) + ": " + result);
        }

        executor.shutdown();
        System.out.println("All tasks completed");
    }
}

// ===== Task.java =====
public record Task(int id, String name) {
    public static final Task POISON_PILL = new Task(-1, "STOP");
}

// ===== Producer.java =====
import java.util.concurrent.BlockingQueue;

public class Producer implements Runnable {
    private final BlockingQueue<Task> queue;
    private final int taskCount;

    public Producer(BlockingQueue<Task> queue, int taskCount) {
        this.queue = queue;
        this.taskCount = taskCount;
    }

    @Override
    public void run() {
        try {
            for (int i = 1; i <= taskCount; i++) {
                Task task = new Task(i, "Task" + i);
                queue.put(task);
                System.out.println("[Producer] Task submitted: " + task);
                Thread.sleep(100);
            }
            queue.put(Task.POISON_PILL);
            System.out.println("[Producer] All tasks submitted");
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

// ===== Consumer.java =====
import java.util.concurrent.BlockingQueue;

public class Consumer implements Runnable {
    private final BlockingQueue<Task> queue;

    public Consumer(BlockingQueue<Task> queue) {
        this.queue = queue;
    }

    @Override
    public void run() {
        try {
            while (true) {
                Task task = queue.take();
                if (task == Task.POISON_PILL) {
                    System.out.println("[Consumer] Stop signal received. Shutting down.");
                    break;
                }
                System.out.println("[Consumer] Processing: " + task);
                Thread.sleep(200); // Simulate processing time
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

