// InternationalDateTime.java
// DateTime i18n: comprehensive exercise for ZonedDateTime and Locale
import java.time.*;
import java.time.format.DateTimeFormatter;
import java.time.format.FormatStyle;
import java.util.Locale;

public class InternationalDateTime {
    public static void main(String[] args) {
        // DateTime in Japan time
        ZonedDateTime jpTime = ZonedDateTime.of(
            2026, 1, 15, 9, 30, 0, 0, ZoneId.of("Asia/Tokyo")
        );

        // Display in each locale/timezone
        System.out.println("=== DateTime Internationalization ===");

        // Japan
        DateTimeFormatter jpFmt = DateTimeFormatter
            .ofPattern("yyyy/M/d EEEE HH:mm z", Locale.JAPAN);
        System.out.println("Japan: " + jpTime.format(jpFmt));

        // US (Central Time)
        ZonedDateTime usTime = jpTime.withZoneSameInstant(ZoneId.of("America/Chicago"));
        DateTimeFormatter usFmt = DateTimeFormatter
            .ofPattern("EEEE, MMMM d, yyyy 'at' h:mm a z", Locale.US);
        System.out.println("US: " + usTime.format(usFmt));

        // France
        ZonedDateTime frTime = jpTime.withZoneSameInstant(ZoneId.of("Europe/Paris"));
        DateTimeFormatter frFmt = DateTimeFormatter
            .ofPattern("EEEE d MMMM yyyy 'à' HH:mm z", Locale.FRANCE);
        System.out.println("France: " + frTime.format(frFmt));
    }
}

