enum ErrorCode { E001, E002, E999 }

// ===== ErrorMessageSystem.java =====

public class ErrorMessageSystem {
    static Map<String, Map<ErrorCode, String>> messages = Map.of(
        "ja", Map.of(
            ErrorCode.E001, "Authentication failed",
            ErrorCode.E002, "Access denied",
            ErrorCode.E999, "An unknown error occurred"
        ),
        "en", Map.of(
            ErrorCode.E001, "Authentication failed",
            ErrorCode.E002, "Access denied",
            ErrorCode.E999, "An unknown error occurred"
        )
    );

    static String getMessage(Locale locale, ErrorCode code) {
        String lang = locale.getLanguage();
        Map<ErrorCode, String> langMessages = messages.getOrDefault(lang, messages.get("en"));
        return langMessages.getOrDefault(code, "ERROR: " + code);
    }

    public static void main(String[] args) {
        Locale[] locales = { Locale.JAPANESE, Locale.ENGLISH };
        String[] labels = { "Japanese", "English" };

        for (int i = 0; i < locales.length; i++) {
            System.out.println("=== " + labels[i] + " ===");
            for (ErrorCode code : ErrorCode.values()) {
                System.out.println(code + ": " + getMessage(locales[i], code));
            }
        }
    }
}

