import java.util.Locale;
import java.util.MissingResourceException;
import java.util.ResourceBundle;

public class MessageDemo {
    public static String getMessage(ResourceBundle bundle, String key, String defaultValue) {
        try {
            return bundle.getString(key);
        } catch (MissingResourceException e) {
            return defaultValue;
        }
    }

    public static void main(String[] args) {
        // Japanese
        ResourceBundle jaBundle = ResourceBundle.getBundle("MessageBundle", Locale.JAPAN);
        System.out.println("=== Japanese ===");
        System.out.println("greeting = " + jaBundle.getString("greeting"));
        System.out.println("error.invalid = " + jaBundle.getString("error.invalid"));

        // English
        ResourceBundle enBundle = ResourceBundle.getBundle("MessageBundle", Locale.US);
        System.out.println("\n=== English ===");
        System.out.println("greeting = " + enBundle.getString("greeting"));
        System.out.println("error.invalid = " + enBundle.getString("error.invalid"));

        // Non-existent key
        System.out.println("\n=== Non-existent Key ===");
        System.out.println("unknown.key = " + getMessage(jaBundle, "unknown.key", "(Default value)"));
    }
}
